import { Suspense } from 'react';
import { TrendingUp, Target, Trophy, Clock, Star, Award, Zap } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';

export const metadata = {
  title: 'Meu Progresso | Nipo School',
  description: 'Acompanhe seu desenvolvimento e conquistas',
};

// Mock data - substituir com dados reais
const stats = {
  licoesCompletadas: 24,
  horasPraticadas: 18,
  conquistasTotal: 12,
  nivelAtual: 3,
  pontosXP: 1250,
  sequenciaAtual: 7,
};

const progressoInstrumentos = [
  { nome: 'Piano', progresso: 75, nivel: 'Intermediário', cor: 'blue' },
  { nome: 'Violino', progresso: 45, nivel: 'Básico', cor: 'green' },
  { nome: 'Flauta', progresso: 30, nivel: 'Iniciante', cor: 'yellow' },
];

const conquistasRecentes = [
  { nome: 'Primeira Semana', data: '2024-01-15', pontos: 50, icone: '🎯' },
  { nome: 'Prática Diária', data: '2024-01-20', pontos: 100, icone: '⭐' },
  { nome: 'Aluno Dedicado', data: '2024-02-01', pontos: 150, icone: '🏆' },
  { nome: 'Mestre da Teoria', data: '2024-02-10', pontos: 200, icone: '📚' },
];

const metasSemanais = [
  { titulo: 'Completar 10 lições', atual: 7, total: 10, cor: 'bg-blue-500' },
  { titulo: 'Praticar 5 horas', atual: 3.5, total: 5, cor: 'bg-green-500' },
  { titulo: 'Obter 3 conquistas', atual: 2, total: 3, cor: 'bg-purple-500' },
];

function ProgressoContent() {
  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
          <TrendingUp className="w-8 h-8 text-blue-600" />
          Meu Progresso
        </h1>
        <p className="text-gray-600 mt-2">
          Acompanhe seu desenvolvimento e conquistas
        </p>
      </div>

      {/* Cards de Estatísticas */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <Card className="bg-gradient-to-br from-blue-50 to-blue-100 border-blue-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-blue-700 font-medium">Lições Completadas</p>
                <p className="text-3xl font-bold text-blue-900">{stats.licoesCompletadas}</p>
              </div>
              <Target className="text-blue-600" size={40} />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-green-50 to-green-100 border-green-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-green-700 font-medium">Horas Praticadas</p>
                <p className="text-3xl font-bold text-green-900">{stats.horasPraticadas}h</p>
              </div>
              <Clock className="text-green-600" size={40} />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-yellow-50 to-yellow-100 border-yellow-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-yellow-700 font-medium">Conquistas</p>
                <p className="text-3xl font-bold text-yellow-900">{stats.conquistasTotal}</p>
              </div>
              <Trophy className="text-yellow-600" size={40} />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-purple-50 to-purple-100 border-purple-200">
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-purple-700 font-medium">Nível Atual</p>
                <p className="text-3xl font-bold text-purple-900">{stats.nivelAtual}</p>
              </div>
              <Award className="text-purple-600" size={40} />
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Progresso por Instrumento */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Target size={24} className="text-blue-600" />
              Progresso por Instrumento
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {progressoInstrumentos.map((item) => (
              <div key={item.nome}>
                <div className="flex justify-between items-center mb-2">
                  <span className="font-medium text-gray-900">{item.nome}</span>
                  <Badge variant="outline">{item.nivel}</Badge>
                </div>
                <Progress value={item.progresso} className="h-3" />
                <p className="text-sm text-gray-600 mt-1">{item.progresso}% concluído</p>
              </div>
            ))}
          </CardContent>
        </Card>

        {/* Metas Semanais */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Zap size={24} className="text-yellow-600" />
              Metas Semanais
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            {metasSemanais.map((meta, index) => (
              <div key={index}>
                <div className="flex justify-between items-center mb-2">
                  <span className="font-medium text-gray-900">{meta.titulo}</span>
                  <span className="text-sm text-gray-600">
                    {meta.atual} / {meta.total}
                  </span>
                </div>
                <Progress 
                  value={(meta.atual / meta.total) * 100} 
                  className="h-3"
                />
              </div>
            ))}
          </CardContent>
        </Card>

        {/* Conquistas Recentes */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Trophy size={24} className="text-yellow-600" />
              Conquistas Recentes
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {conquistasRecentes.map((conquista, index) => (
                <div
                  key={index}
                  className="flex items-center gap-4 p-4 border rounded-lg hover:shadow-md transition-shadow bg-gradient-to-r from-gray-50 to-white"
                >
                  <div className="text-4xl">{conquista.icone}</div>
                  <div className="flex-1">
                    <h4 className="font-semibold text-gray-900">{conquista.nome}</h4>
                    <p className="text-sm text-gray-600">
                      {new Date(conquista.data).toLocaleDateString('pt-BR')}
                    </p>
                  </div>
                  <Badge className="bg-yellow-100 text-yellow-800 border-yellow-200">
                    +{conquista.pontos} XP
                  </Badge>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Sequência Atual */}
        <Card className="bg-gradient-to-br from-orange-50 to-orange-100 border-orange-200">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-orange-900">
              <Star size={24} className="text-orange-600" />
              Sequência de Prática
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-center">
              <p className="text-6xl font-bold text-orange-600 mb-2">
                {stats.sequenciaAtual}
              </p>
              <p className="text-lg text-orange-800">dias consecutivos</p>
              <p className="text-sm text-orange-700 mt-4">
                Continue assim! Pratique hoje para manter sua sequência 🔥
              </p>
            </div>
          </CardContent>
        </Card>

        {/* Nível e XP */}
        <Card className="bg-gradient-to-br from-indigo-50 to-indigo-100 border-indigo-200">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-indigo-900">
              <Award size={24} className="text-indigo-600" />
              Experiência (XP)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <div>
                <div className="flex justify-between items-center mb-2">
                  <span className="text-sm text-indigo-700 font-medium">
                    Nível {stats.nivelAtual}
                  </span>
                  <span className="text-sm text-indigo-700 font-medium">
                    {stats.pontosXP} / 2000 XP
                  </span>
                </div>
                <Progress value={(stats.pontosXP / 2000) * 100} className="h-3" />
              </div>
              <p className="text-sm text-indigo-700">
                Faltam <strong>{2000 - stats.pontosXP} XP</strong> para o próximo nível!
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

export default function ProgressoPage() {
  return (
    <Suspense fallback={<div className="p-8">Carregando progresso...</div>}>
      <ProgressoContent />
    </Suspense>
  );
}
